1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	};
7	
8	const COMPONENT_PREMIUM = 25;
9	const COMPONENT_BLOCK_PREMIUM = 60;
10	const CURSED_SURCHARGE_RATE = 0.5;
11	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const LOYALTY_DISCOUNT_RATE = 0.2;
14	const LOYALTY_THRESHOLD = 2;
15	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
16	const PROCESSING_FEE = 5;
17	
18	interface Item {
19	  type: string;
20	  cursed?: boolean;
21	  enchantment?: number;
22	}
23	
24	function isComponent(type: string): boolean {
25	  return !(type in BASE_PREMIUMS);
26	}
27	
28	function mainItemPremium(items: Item[]): number {
29	  return items
30	    .filter((item) => !isComponent(item.type))
31	    .reduce((sum, item) => sum + itemBasePremium(item), 0);
32	}
33	
34	function componentPremium(items: Item[]): number {
35	  const counts = new Map<string, number>();
36	  for (const item of items) {
37	    if (isComponent(item.type)) {
38	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
39	    }
40	  }
41	  let total = 0;
42	  for (const [, count] of counts) {
43	    total += count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
44	  }
45	  return total;
46	}
47	
48	function itemBasePremium(item: Item): number {
49	  return BASE_PREMIUMS[item.type] ?? COMPONENT_PREMIUM;
50	}
51	
52	function singleItemSurcharge(item: Item): number {
53	  const base = itemBasePremium(item);
54	  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
55	    + ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
56	}
57	
58	function itemSurcharges(items: Item[]): number {
59	  return items.reduce((sum, item) => sum + singleItemSurcharge(item), 0);
60	}
61	
62	function computeQuotePremium(items: Item[], customer: { yearsWithMHPCO: number }): number {
63	  const basePremium = mainItemPremium(items) + componentPremium(items);
64	  const surcharges = itemSurcharges(items);
65	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
66	  return Math.ceil(basePremium + surcharges + basePremium * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount + PROCESSING_FEE);
67	}
68	
69	export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items?: Item[] }> }) {
70	  const results = scenario.steps.map((step) => ({
71	    premium: computeQuotePremium(step.items ?? [], scenario.customer),
72	  }));
73	  return { results };
74	}
